package com.example.projecthub.model;

import jakarta.persistence.*;
import lombok.Data;

@Entity
@Data
public class Review {

    @Id
    @GeneratedValue(strategy = GenerationType.AUTO)
    private Long id;
    private int rating;

    private String comment;

    @ManyToOne
    @JoinColumn(name = "project_id")
    private Project project;

    @ManyToOne
    @JoinColumn(name = "user_id")
    private User user;
}

package com.example.projecthub.model;

import jakarta.persistence.*;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.time.LocalDateTime;

/**
 * Entity representing a user's review/rating for a project.
 * 
 * Contains:
 * - Rating score (1-5 scale)
 * - Comment text provided by reviewer
 * - Relationships to user and project
 * - Audit timestamps for tracking review lifecycle
 * 
 * Enforces:
 * - One review per user per project (business logic validation)
 * - Rating must be between 1 and 5
 * - Non-empty comment field
 * 
 * @author Project Hub Team
 * @version 1.0
 */
@Entity
@Data
@NoArgsConstructor
@Table(name = "reviews", uniqueConstraints = @UniqueConstraint(columnNames = {"user_id", "project_id"}))
public class Review {

    /**
     * Unique identifier for the review.
     * Auto-generated primary key.
     */
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    /**
     * Rating score from 1 to 5.
     * 1 = Poor, 5 = Excellent
     * Must be validated in service layer.
     */
    @Column(nullable = false)
    private int rating;

    /**
     * Detailed review comment provided by the reviewer.
     * Can contain feedback, pros, cons, and recommendations.
     */
    @Column(nullable = false, length = 1000)
    private String comment;

    /**
     * Reference to the project being reviewed.
     * Multiple reviews can reference same project.
     * Cascade delete is handled by Project entity.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "project_id", nullable = false)
    private Project project;

    /**
     * Reference to the user who submitted the review.
     * Each user can have multiple reviews across different projects.
     */
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "user_id", nullable = false)
    private User user;

    /**
     * Timestamp when the review was created.
     * Set automatically on entity creation.
     */
    @Column(nullable = false, updatable = false)
    private LocalDateTime createdAt;

    /**
     * Timestamp when the review was last updated.
     * Updated whenever the review is modified.
     */
    @Column(nullable = false)
    private LocalDateTime updatedAt;

    /**
     * Lifecycle callback - sets creation timestamp before persisting.
     * Called once when review is first saved to database.
     */
    @PrePersist
    protected void onCreate() {
        this.createdAt = LocalDateTime.now();
        this.updatedAt = LocalDateTime.now();
    }

    /**
     * Lifecycle callback - updates modification timestamp before update.
     * Called every time the review is updated in database.
     */
    @PreUpdate
    protected void onUpdate() {
        this.updatedAt = LocalDateTime.now();
    }
}

package com.example.projecthub.controller;

import com.example.projecthub.dto.project.ProjectDTO;
import com.example.projecthub.dto.project.ProjectDetailsResponse;
import com.example.projecthub.dto.project.ProjectResponse;
import com.example.projecthub.dto.projectfile.ProjectFileDTO;
import com.example.projecthub.service.project.ProjectService;
import com.example.projecthub.service.purchase.PurchaseService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Slf4j
@RestController
@RequiredArgsConstructor
@RequestMapping("/api/seller")
public class SellerController {

    private final ProjectService projectService;
    private final PurchaseService purchaseService;

    /**
     * Creates a new project
     * @param projectDTO project data as JSON
     * @param file project image file
     * @return created project
     */
    @PostMapping(value = "/create/project", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<?> createProject(
            @RequestPart("project") @Valid ProjectDTO projectDTO,
            @RequestPart("file") MultipartFile file) {

        try {
            log.info("Received request to create project: {}", projectDTO.getTitle());

            if (file.isEmpty()) {
                return ResponseEntity.badRequest()
                        .body(createErrorResponse("Project image file is required"));
            }

            ProjectDTO createdProject = projectService.createProject(projectDTO, file);
            log.info("Project created successfully with ID: {}", createdProject.getId());

            return ResponseEntity.status(HttpStatus.CREATED).body(createdProject);

        } catch (IOException e) {
            log.error("Error uploading file: ", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(createErrorResponse("Failed to upload file: " + e.getMessage()));
        } catch (Exception e) {
            log.error("Error creating project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    /**
     * Adds a file to an existing project
     * @param projectFileDTO file metadata as JSON
     * @param file the file to upload
     * @param userId user ID from authentication (or pass via DTO for testing)
     * @return created project file
     */
    @PostMapping(value = "/project/add-file", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<?> addProjectFile(
            @RequestPart("projectFile") @Valid ProjectFileDTO projectFileDTO,
            @RequestPart("file") MultipartFile file,
            @RequestParam Long userId
            ) {  // In production, get from @AuthenticationPrincipal

        try {
            log.info("Received request to add file to project ID: {}", projectFileDTO.getProjectId());

            if (file.isEmpty()) {
                return ResponseEntity.badRequest()
                        .body(createErrorResponse("File is required"));
            }

            ProjectFileDTO addedFile = projectService.addFileToProject(projectFileDTO, file, userId);
            log.info("File added successfully to project");

            return ResponseEntity.status(HttpStatus.CREATED).body(addedFile);

        } catch (IOException e) {
            log.error("Error uploading file: ", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(createErrorResponse("Failed to upload file: " + e.getMessage()));
        } catch (Exception e) {
            log.error("Error adding file to project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @GetMapping("/{userId}/projects")
    public ResponseEntity<?>getMyProjects(@PathVariable("userId") Long userId) {
        List<ProjectResponse> myProjects = projectService.getMyProjects(userId);
//        log.info("My projects: {}", myProjects);
        return ResponseEntity.status(HttpStatus.OK).body(myProjects);
    }

    @GetMapping("/project/{projectId}")
    public ResponseEntity<?> getProjectDetails(@PathVariable("projectId") Long projectId) {
        try {
            ProjectDetailsResponse projectDetails = projectService.getProjectDetailsById(projectId);
            return ResponseEntity.ok(projectDetails);
        } catch (Exception e) {
            log.error("Error fetching project details: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @PutMapping("/project/{projectId}/submit-for-review")
    public ResponseEntity<?> submitProjectForReview(@PathVariable Long projectId) {
        try {
            log.info("Admin submitting project ID: {}", projectId);
            ProjectResponse projectResponse = projectService.submitForReview(projectId);
            return ResponseEntity.ok(projectResponse);
        }catch (Exception e) {
            log.error("Error submitting project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @PutMapping("/project/{projectId}/withdraw")
    public ResponseEntity<?> withdrawFromReview(@PathVariable Long projectId) {
        try {
            log.info("Withdrawn project ID: {}", projectId);
            ProjectResponse projectResponse = projectService.withdrawFromReview(projectId);
            return ResponseEntity.ok(projectResponse);
        }catch (Exception e) {
            log.error("Error withdrawnFromReview project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @GetMapping("/stats")
    public ResponseEntity<?>getStats(){
        return ResponseEntity.ok(Map
                .of("today", purchaseService.getTodaySales(),
                        "thisWeek",purchaseService.getWeeklySales(),
                        "thisMonth",purchaseService.getMonthlySales()
                )
        );
    }

    /**
     * Helper method to create error response
     */
    private Map<String, String> createErrorResponse(String message) {
        Map<String, String> error = new HashMap<>();
        error.put("error", message);
        error.put("timestamp", java.time.LocalDateTime.now().toString());
        return error;
    }
}

package com.example.projecthub.controller;

import com.example.projecthub.dto.project.ProjectDTO;
import com.example.projecthub.dto.project.ProjectDetailsResponse;
import com.example.projecthub.dto.project.ProjectResponse;
import com.example.projecthub.dto.projectfile.ProjectFileDTO;
import com.example.projecthub.service.project.ProjectService;
import com.example.projecthub.service.purchase.PurchaseService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

@Slf4j
@RestController
@RequiredArgsConstructor
@RequestMapping("/api/seller")
public class SellerController {

    private final ProjectService projectService;
    private final PurchaseService purchaseService;

    /**
     * Creates a new project
     * @param projectDTO project data as JSON
     * @param file project image file
     * @return created project
     */
    @PostMapping(value = "/create/project", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<?> createProject(
            @RequestPart("project") @Valid ProjectDTO projectDTO,
            @RequestPart("file") MultipartFile file) {

        try {
            log.info("Received request to create project: {}", projectDTO.getTitle());

            if (file.isEmpty()) {
                return ResponseEntity.badRequest()
                        .body(createErrorResponse("Project image file is required"));
            }

            ProjectDTO createdProject = projectService.createProject(projectDTO, file);
            log.info("Project created successfully with ID: {}", createdProject.getId());

            return ResponseEntity.status(HttpStatus.CREATED).body(createdProject);

        } catch (IOException e) {
            log.error("Error uploading file: ", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(createErrorResponse("Failed to upload file: " + e.getMessage()));
        } catch (Exception e) {
            log.error("Error creating project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    /**
     * Adds a file to an existing project
     * @param projectFileDTO file metadata as JSON
     * @param file the file to upload
     * @param userDetails authenticated user details
     * @return created project file
     */
    @PostMapping(value = "/project/add-file", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<?> addProjectFile(
            @RequestPart("projectFile") @Valid ProjectFileDTO projectFileDTO,
            @RequestPart("file") MultipartFile file,
            @AuthenticationPrincipal UserDetails userDetails
            ) {

        try {
            if (userDetails == null) {
                return ResponseEntity.status(401)
                        .body(createErrorResponse("User authentication required"));
            }

            // Extract userId from authenticated principal
            // Note: You may need to create a custom UserDetails that includes the ID
            // For now, we'll assume the username can be used to fetch the user
            Long userId = extractUserIdFromDetails(userDetails);

            log.info("Received request to add file to project ID: {} by user: {}", 
                    projectFileDTO.getProjectId(), userDetails.getUsername());

            if (file.isEmpty()) {
                return ResponseEntity.badRequest()
                        .body(createErrorResponse("File is required"));
            }

            ProjectFileDTO addedFile = projectService.addFileToProject(projectFileDTO, file, userId);
            log.info("File added successfully to project");

            return ResponseEntity.status(HttpStatus.CREATED).body(addedFile);

        } catch (IOException e) {
            log.error("Error uploading file: ", e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(createErrorResponse("Failed to upload file: " + e.getMessage()));
        } catch (Exception e) {
            log.error("Error adding file to project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    /**
     * Extract user ID from authenticated UserDetails
     * This is a helper method - ensure your CustomUserDetails includes the ID
     */
    private Long extractUserIdFromDetails(UserDetails userDetails) {
        // If using custom MyUser class from JWT, cast and extract ID
        if (userDetails instanceof com.example.projecthub.jwt.MyUser) {
            return ((com.example.projecthub.jwt.MyUser) userDetails).getId();
        }
        // Fallback: Return 0 or throw exception
        throw new RuntimeException("Cannot extract user ID from authentication principal");
    }

    @GetMapping("/{userId}/projects")
    public ResponseEntity<?>getMyProjects(@PathVariable("userId") Long userId) {
        List<ProjectResponse> myProjects = projectService.getMyProjects(userId);
//        log.info("My projects: {}", myProjects);
        return ResponseEntity.status(HttpStatus.OK).body(myProjects);
    }

    @GetMapping("/project/{projectId}")
    public ResponseEntity<?> getProjectDetails(@PathVariable("projectId") Long projectId) {
        try {
            ProjectDetailsResponse projectDetails = projectService.getProjectDetailsById(projectId);
            return ResponseEntity.ok(projectDetails);
        } catch (Exception e) {
            log.error("Error fetching project details: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @PutMapping("/project/{projectId}/submit-for-review")
    public ResponseEntity<?> submitProjectForReview(@PathVariable Long projectId) {
        try {
            log.info("Admin submitting project ID: {}", projectId);
            ProjectResponse projectResponse = projectService.submitForReview(projectId);
            return ResponseEntity.ok(projectResponse);
        }catch (Exception e) {
            log.error("Error submitting project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @PutMapping("/project/{projectId}/withdraw")
    public ResponseEntity<?> withdrawFromReview(@PathVariable Long projectId) {
        try {
            log.info("Withdrawn project ID: {}", projectId);
            ProjectResponse projectResponse = projectService.withdrawFromReview(projectId);
            return ResponseEntity.ok(projectResponse);
        }catch (Exception e) {
            log.error("Error withdrawnFromReview project: ", e);
            return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body(createErrorResponse(e.getMessage()));
        }
    }

    @GetMapping("/stats")
    public ResponseEntity<?>getStats(){
        return ResponseEntity.ok(Map
                .of("today", purchaseService.getTodaySales(),
                        "thisWeek",purchaseService.getWeeklySales(),
                        "thisMonth",purchaseService.getMonthlySales()
                )
        );
    }

    /**
     * Helper method to create error response
     */
    private Map<String, String> createErrorResponse(String message) {
        Map<String, String> error = new HashMap<>();
        error.put("error", message);
        error.put("timestamp", java.time.LocalDateTime.now().toString());
        return error;
    }
}

package com.example.projecthub.helper;

import com.example.projecthub.exception.ValidationException;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.StandardCopyOption;
import java.util.Arrays;
import java.util.List;
import java.util.UUID;

@Slf4j
@Component
public class FileHelper {

    @Value("${filePath}")
    private String filePath;

    @Value("${max.file.size:104857600}") // 100MB default for project files
    private long maxFileSize;

    // Allow various file types for project files
    private static final List<String> ALLOWED_EXTENSIONS = Arrays.asList(
            // Archives
            ".zip", ".rar", ".7z", ".tar", ".gz",
            // Source code
            ".java", ".py", ".js", ".ts", ".html", ".css", ".cpp", ".c", ".h",
            // Executables
            ".exe", ".jar", ".apk", ".war",
            // Documents
            ".pdf", ".doc", ".docx", ".txt", ".md",
            // Database
            ".sql", ".db", ".sqlite",
            // Configuration
            ".json", ".xml", ".yaml", ".yml", ".env", ".properties",
            // Images (for project screenshots)
            ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".svg",
            // Videos
            ".mp4", ".avi", ".mov", ".wmv"
    );

    /**
     * Uploads a file to the configured directory
     * @param file the file to upload
     * @return the relative URL path to access the file
     * @throws IOException if file upload fails
     */
    public String uploadFile(MultipartFile file) throws IOException {
        log.info("Attempting to upload file: {}", file.getOriginalFilename());

        // Validate file
        validateFile(file);

        // Ensure upload directory exists
        Path uploadPath = Paths.get(filePath);
        log.debug("Upload path: {}", uploadPath.toAbsolutePath());

        if (!Files.exists(uploadPath)) {
            Files.createDirectories(uploadPath);
            log.info("Created upload directory: {}", uploadPath.toAbsolutePath());
        }

        // Generate unique filename
        String originalFilename = file.getOriginalFilename();
        String fileExtension = getFileExtension(originalFilename);
        String uniqueFilename = UUID.randomUUID().toString() + fileExtension;

        // Save file
        Path targetPath = uploadPath.resolve(uniqueFilename);
        log.debug("Saving file to: {}", targetPath.toAbsolutePath());

        Files.copy(file.getInputStream(), targetPath, StandardCopyOption.REPLACE_EXISTING);

        log.info("File uploaded successfully: {}", uniqueFilename);
        return "/files/" + uniqueFilename;
    }

    /**
     * Validates the uploaded file
     * @param file the file to validate
     * @throws ValidationException if validation fails
     */
    private void validateFile(MultipartFile file) {
        if (file == null || file.isEmpty()) {
            throw new ValidationException("File is required and cannot be empty");
        }

        // Check file size
        if (file.getSize() > maxFileSize) {
            throw new ValidationException(
                    String.format("File size exceeds maximum allowed size of %d bytes (%.2f MB)",
                            maxFileSize, maxFileSize / (1024.0 * 1024.0))
            );
        }

        // Check file extension
        String filename = file.getOriginalFilename();
        if (filename == null || filename.trim().isEmpty()) {
            throw new ValidationException("File must have a valid filename");
        }

        String extension = getFileExtension(filename).toLowerCase();
        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            throw new ValidationException(
                    String.format("File extension %s is not allowed. Allowed extensions: %s",
                            extension, ALLOWED_EXTENSIONS)
            );
        }
    }

    /**
     * Extracts file extension from filename
     * @param filename the filename
     * @return the file extension including the dot
     */
    private String getFileExtension(String filename) {
        if (filename == null || filename.isEmpty()) {
            return "";
        }

        int lastDotIndex = filename.lastIndexOf('.');
        if (lastDotIndex == -1 || lastDotIndex == filename.length() - 1) {
            return "";
        }

        return filename.substring(lastDotIndex).toLowerCase();
    }

    /**
     * Deletes a file from the upload directory
     * @param fileUrl the relative URL of the file
     * @return true if deletion was successful
     */
    public boolean deleteFile(String fileUrl) {
        try {
            if (fileUrl == null || fileUrl.isEmpty()) {
                return false;
            }

            // Extract filename from URL
            String filename = fileUrl.replace("/files/", "");
            Path filePath = Paths.get(this.filePath).resolve(filename);

            if (Files.exists(filePath)) {
                Files.delete(filePath);
                log.info("File deleted successfully: {}", filename);
                return true;
            }

            log.warn("File not found for deletion: {}", filename);
            return false;

        } catch (IOException e) {
            log.error("Error deleting file: {}", fileUrl, e);
            return false;
        }
    }
}

package com.example.projecthub.helper;

import com.example.projecthub.exception.ValidationException;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.nio.file.Files;
