        String fileExtension = getFileExtension(originalFilename);
        String uniqueFilename = UUID.randomUUID().toString() + fileExtension;

        // Save file
        Path targetPath = uploadPath.resolve(uniqueFilename);
        log.debug("Saving file to: {}", targetPath.toAbsolutePath());

        Files.copy(file.getInputStream(), targetPath, StandardCopyOption.REPLACE_EXISTING);

        log.info("File uploaded successfully: {}", uniqueFilename);
        return "/files/" + uniqueFilename;
    }

    /**
     * Validates the uploaded file
     * @param file the file to validate
     * @throws ValidationException if validation fails
     */
    private void validateFile(MultipartFile file) {
        if (file == null || file.isEmpty()) {
            throw new ValidationException("File is required and cannot be empty");
        }

        // Check file size
        if (file.getSize() > maxFileSize) {
            throw new ValidationException(
                    String.format("File size exceeds maximum allowed size of %d bytes (%.2f MB)",
                            maxFileSize, maxFileSize / (1024.0 * 1024.0))
            );
        }

        // Check file extension
        String filename = file.getOriginalFilename();
        if (filename == null || filename.trim().isEmpty()) {
            throw new ValidationException("File must have a valid filename");
        }

        String extension = getFileExtension(filename).toLowerCase();
        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            throw new ValidationException(
                    String.format("File extension %s is not allowed. Allowed extensions: %s",
                            extension, ALLOWED_EXTENSIONS)
            );
        }
    }

    /**
     * Extracts file extension from filename
     * @param filename the filename
     * @return the file extension including the dot
     */
    private String getFileExtension(String filename) {
        if (filename == null || filename.isEmpty()) {
            return "";
        }

        int lastDotIndex = filename.lastIndexOf('.');
        if (lastDotIndex == -1 || lastDotIndex == filename.length() - 1) {
            return "";
        }

        return filename.substring(lastDotIndex).toLowerCase();
    }

    /**
     * Deletes a file from the upload directory
     * @param fileUrl the relative URL of the file
     * @return true if deletion was successful
     */
    public boolean deleteFile(String fileUrl) {
        try {
            if (fileUrl == null || fileUrl.isEmpty()) {
                return false;
            }

            // Extract filename from URL
            String filename = fileUrl.replace("/files/", "");
            Path filePath = Paths.get(this.filePath).resolve(filename);

            if (Files.exists(filePath)) {
                Files.delete(filePath);
                log.info("File deleted successfully: {}", filename);
                return true;
            }

            log.warn("File not found for deletion: {}", filename);
            return false;

        } catch (IOException e) {
            log.error("Error deleting file: {}", fileUrl, e);
            return false;
        }
    }
}

package com.example.projecthub.jwt;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

/**
 * JWT Authentication Filter
 * Intercepts requests and validates JWT tokens from Authorization header
 */
@Component
@RequiredArgsConstructor
@Slf4j
public class JwtAuthenticationFilter extends OncePerRequestFilter {

    private static final String BEARER_PREFIX = "Bearer ";
    private static final String AUTHORIZATION_HEADER = "Authorization";
    private static final int BEARER_LENGTH = 7;

    private final JwtUtils jwtUtils;
    private final UserDetailsService userDetailsService;

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) 
            throws ServletException, IOException {
        try {
            String authHeader = request.getHeader(AUTHORIZATION_HEADER);

            if (authHeader == null || !authHeader.startsWith(BEARER_PREFIX)) {
                filterChain.doFilter(request, response);
                return;
            }

            String token = authHeader.substring(BEARER_LENGTH);
            String username = jwtUtils.extractUsername(token);

            if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {
                UserDetails userDetails = userDetailsService.loadUserByUsername(username);

                if (jwtUtils.isTokenValid(token, userDetails)) {
                    UsernamePasswordAuthenticationToken authToken = 
                        new UsernamePasswordAuthenticationToken(
                            userDetails,
                            null,
                            userDetails.getAuthorities()
                        );

                    authToken.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
                    SecurityContextHolder.getContext().setAuthentication(authToken);
                    log.debug("JWT Token validated successfully for user: {}", username);
                } else {
                    log.warn("JWT Token validation failed for user: {}", username);
                }
            }

            filterChain.doFilter(request, response);
        } catch (Exception e) {
            log.error("Error processing JWT token: {}", e.getMessage(), e);
            filterChain.doFilter(request, response);
        }
    }
}

package com.example.projecthub.jwt;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.web.authentication.WebAuthenticationDetailsSource;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

/**
 * JWT Authentication Filter
 * Intercepts requests and validates JWT tokens from Authorization header
 */
@Component
@RequiredArgsConstructor
@Slf4j
public class JwtAuthenticationFilter extends OncePerRequestFilter {

    private static final String BEARER_PREFIX = "Bearer ";
    private static final String AUTHORIZATION_HEADER = "Authorization";
    private static final int BEARER_LENGTH = 7;

    private final JwtUtils jwtUtils;
    private final UserDetailsService userDetailsService;

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) 
            throws ServletException, IOException {
        try {
            String authHeader = request.getHeader(AUTHORIZATION_HEADER);

            if (authHeader == null || !authHeader.startsWith(BEARER_PREFIX)) {
                filterChain.doFilter(request, response);
                return;
            }

            String token = authHeader.substring(BEARER_LENGTH);
            String username = jwtUtils.extractUsername(token);

            if (username != null && SecurityContextHolder.getContext().getAuthentication() == null) {
                UserDetails userDetails = userDetailsService.loadUserByUsername(username);

                if (jwtUtils.isTokenValid(token, userDetails)) {
                    UsernamePasswordAuthenticationToken authToken = 
                        new UsernamePasswordAuthenticationToken(
                            userDetails,
                            null,
                            userDetails.getAuthorities()
                        );

                    authToken.setDetails(new WebAuthenticationDetailsSource().buildDetails(request));
                    SecurityContextHolder.getContext().setAuthentication(authToken);
                    log.debug("JWT Token validated successfully for user: {}", username);
                } else {
                    log.warn("JWT Token validation failed for user: {} at endpoint: {}", username, request.getRequestURI());
                    response.sendError(401, "Invalid or expired token");
                    return;
                }
            }

            filterChain.doFilter(request, response);
        } catch (Exception e) {
            log.error("Error processing JWT token for endpoint {}: {}", request.getRequestURI(), e.getMessage());
            response.sendError(401, "Authentication failed: " + e.getMessage());
        }
    }
}

package com.example.projecthub.jwt;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.io.Decoders;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Component;

import java.security.Key;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;
import java.util.function.Function;

@Component
public class JwtUtils {

    @Value("${jwt.secret:404E635266556A586E3272357538782F413F4428472B4B6250645367566B5970}")
    private String secretKey;

    @Value("${jwt.access-token-expiration:900000}")
    private long accessTokenExpiration;

    @Value("${jwt.refresh-token-expiration:604800000}")
    private long refreshTokenExpiration;

    private static final String TOKEN_TYPE_ACCESS = "ACCESS";
    private static final String TOKEN_TYPE_REFRESH = "REFRESH";
    private static final String CLAIM_TOKEN_TYPE = "token_type";

    /**
     * Generate access token for authenticated user
     * Default expiration: 15 minutes (900000ms)
     */
    public String generateAccessToken(UserDetails userDetails) {
        Map<String, Object> claims = new HashMap<>();
        claims.put(CLAIM_TOKEN_TYPE, TOKEN_TYPE_ACCESS);
        return buildToken(claims, userDetails, accessTokenExpiration);
    }

    /**
     * Generate access token with additional claims
     */
    public String generateAccessToken(Map<String, Object> extraClaims, UserDetails userDetails) {
        extraClaims.put(CLAIM_TOKEN_TYPE, TOKEN_TYPE_ACCESS);
        return buildToken(extraClaims, userDetails, accessTokenExpiration);
    }

    /**
     * Generate refresh token for token refresh mechanism
     * Default expiration: 7 days (604800000ms)
     */
    public String generateRefreshToken(UserDetails userDetails) {
        Map<String, Object> claims = new HashMap<>();
        claims.put(CLAIM_TOKEN_TYPE, TOKEN_TYPE_REFRESH);
        return buildToken(claims, userDetails, refreshTokenExpiration);
    }

    /**
     * Validate token against user details
     * Checks username match and token expiration
     */
    public boolean isTokenValid(String token, UserDetails userDetails) {
        try {
            String username = extractUsername(token);
            return username.equals(userDetails.getUsername()) && !isTokenExpired(token);
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Build JWT token with claims and expiration
     */
    private String buildToken(
            Map<String, Object> claims,
            UserDetails userDetails,
            long expirationTime) {
        return Jwts
                .builder()
                .setClaims(claims)
                .setSubject(userDetails.getUsername())
                .setIssuedAt(new Date(System.currentTimeMillis()))
                .setExpiration(new Date(System.currentTimeMillis() + expirationTime))
                .signWith(getSignInKey(), SignatureAlgorithm.HS256)
                .compact();
    }

    /**
     * Get the signing key from base64 decoded secret
     */
    private Key getSignInKey() {
        byte[] secretKeys = Decoders.BASE64.decode(secretKey);
        return Keys.hmacShaKeyFor(secretKeys);
    }

    /**
     * Check if token has expired
     */
    public boolean isTokenExpired(String token) {
        return extractExpiration(token).before(new Date());
    }

    /**
     * Extract expiration date from token
     */
    public Date extractExpiration(String token) {
        return extractClaims(token, Claims::getExpiration);
    }

    /**
     * Extract username (subject) from token
     */
    public String extractUsername(String token) {
        return extractClaims(token, Claims::getSubject);
    }

    /**
     * Extract specific claim from token
     */
    public <T> T extractClaims(String token, Function<Claims, T> claimsResolver) {
        final Claims claims = extractAllClaims(token);
        return claimsResolver.apply(claims);
    }

    /**
     * Extract all claims from JWT token
     * Decodes and validates the token signature
     */
    private Claims extractAllClaims(String token) {
        return Jwts
                .parserBuilder()
                .setSigningKey(getSignInKey())
                .build()
                .parseClaimsJws(token)
                .getBody();
    }
}

package com.example.projecthub.jwt;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.io.Decoders;
import io.jsonwebtoken.security.Keys;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Component;

import java.security.Key;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;
import java.util.function.Function;

@Component
public class JwtUtils {

    @Value("${jwt.secret:404E635266556A586E3272357538782F413F4428472B4B6250645367566B5970}")
    private String secretKey;

    @Value("${jwt.access-token-expiration:900000}")
    private long accessTokenExpiration;

    @Value("${jwt.refresh-token-expiration:604800000}")
    private long refreshTokenExpiration;

    private static final String TOKEN_TYPE_ACCESS = "ACCESS";
    private static final String TOKEN_TYPE_REFRESH = "REFRESH";
    private static final String CLAIM_TOKEN_TYPE = "token_type";

    /**
     * Generate access token for authenticated user
     * Default expiration: 15 minutes (900000ms)
     */
    public String generateAccessToken(UserDetails userDetails) {
        Map<String, Object> claims = new HashMap<>();
        claims.put(CLAIM_TOKEN_TYPE, TOKEN_TYPE_ACCESS);
        return buildToken(claims, userDetails, accessTokenExpiration);
    }

    /**
     * Generate access token with additional claims
     */
    public String generateAccessToken(Map<String, Object> extraClaims, UserDetails userDetails) {
        extraClaims.put(CLAIM_TOKEN_TYPE, TOKEN_TYPE_ACCESS);
        return buildToken(extraClaims, userDetails, accessTokenExpiration);
    }

    /**
     * Generate refresh token for token refresh mechanism
     * Default expiration: 7 days (604800000ms)
     */
    public String generateRefreshToken(UserDetails userDetails) {
        Map<String, Object> claims = new HashMap<>();
        claims.put(CLAIM_TOKEN_TYPE, TOKEN_TYPE_REFRESH);
        return buildToken(claims, userDetails, refreshTokenExpiration);
    }

    /**
     * Validate token against user details
     * Checks username match and token expiration and token type
     */
    public boolean isTokenValid(String token, UserDetails userDetails) {
        try {
            String username = extractUsername(token);
            return username != null && 
                   username.equals(userDetails.getUsername()) && 
                   !isTokenExpired(token) &&
                   isTokenTypeValid(token, TOKEN_TYPE_ACCESS);
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Validate refresh token specifically
     * Checks if token is marked as refresh type
     */
    public boolean isRefreshTokenValid(String token, UserDetails userDetails) {
        try {
            String username = extractUsername(token);
            return username != null && 
                   username.equals(userDetails.getUsername()) && 
                   !isTokenExpired(token) &&
                   isTokenTypeValid(token, TOKEN_TYPE_REFRESH);
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Verify that token has the expected type claim
     */
    private boolean isTokenTypeValid(String token, String expectedType) {
        try {
            String tokenType = extractClaims(token, claims -> claims.get(CLAIM_TOKEN_TYPE, String.class));
            return expectedType.equals(tokenType);
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Build JWT token with claims and expiration
     */
    private String buildToken(
            Map<String, Object> claims,
            UserDetails userDetails,
            long expirationTime) {
        return Jwts
                .builder()
                .setClaims(claims)
                .setSubject(userDetails.getUsername())
                .setIssuedAt(new Date(System.currentTimeMillis()))
                .setExpiration(new Date(System.currentTimeMillis() + expirationTime))
                .signWith(getSignInKey(), SignatureAlgorithm.HS256)
                .compact();
    }

    /**
     * Get the signing key from base64 decoded secret
     */
    private Key getSignInKey() {
        byte[] secretKeys = Decoders.BASE64.decode(secretKey);
        return Keys.hmacShaKeyFor(secretKeys);
    }

    /**
     * Check if token has expired
     */
    public boolean isTokenExpired(String token) {
        return extractExpiration(token).before(new Date());
    }

    /**
     * Extract expiration date from token
     */
    public Date extractExpiration(String token) {
        return extractClaims(token, Claims::getExpiration);
    }

    /**
     * Extract username (subject) from token
     */
    public String extractUsername(String token) {
        return extractClaims(token, Claims::getSubject);
    }

    /**
     * Extract specific claim from token
     */
    public <T> T extractClaims(String token, Function<Claims, T> claimsResolver) {
        final Claims claims = extractAllClaims(token);
        return claimsResolver.apply(claims);
    }

    /**
     * Extract all claims from JWT token
     * Decodes and validates the token signature
     */
    private Claims extractAllClaims(String token) {
        return Jwts
                .parserBuilder()
                .setSigningKey(getSignInKey())
                .build()
                .parseClaimsJws(token)
                .getBody();
    }
}

package com.example.projecthub.model;

import jakarta.persistence.*;
import lombok.Data;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

@Data
@Entity

public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    private String username;
    private String email;
    private String password;
    private String fullName;
    private String bio;
    private String profileImgUrl;
    private boolean isActive;
    private LocalDateTime createdAt;
    private LocalDateTime updatedAt;
    private Double balance=0.0;
    @ManyToMany(fetch = FetchType.EAGER)
    @JoinTable(
            name = "user_roles",
            joinColumns = @JoinColumn(name = "user_id"),
            inverseJoinColumns = @JoinColumn(name = "role_id")
    )
    private Set<Role> roles;

    @Enumerated(EnumType.STRING)
    private Status status=Status.PENDING;

    @OneToMany(mappedBy = "seller",cascade = CascadeType.ALL)
    private List<Project>uploadedProjects=new ArrayList<>();

    @OneToMany(mappedBy = "buyer",cascade = CascadeType.ALL)
    private List<Purchase>purchases=new ArrayList<>();

    @OneToMany(mappedBy = "user",cascade = CascadeType.ALL)
    private List<Review>reviews=new ArrayList<>();

    @PrePersist
    public void onCreate() {
        this.createdAt = LocalDateTime.now();
        this.updatedAt = LocalDateTime.now();
    }

    @PreUpdate
    public void onUpdate() {
        this.updatedAt = LocalDateTime.now();
    }


    public boolean hasPurchased(Project project) {
        return purchases.stream()
                .anyMatch(p->p.getProject().getId().equals(project.getId())
                && p.canDownload());
    }

    public void addBalance(double balance) {
        this.balance+=balance;
    }

    public void deductBalance(double balance) {
        this.balance-=balance;
    }

}

package com.example.projecthub.model;

import jakarta.persistence.*;
import lombok.Data;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Set;

@Data
@Entity

public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;
    private String username;
    private String email;
    private String password;
    private String fullName;
    private String bio;
    private String profileImgUrl;
    private boolean isActive;
    private LocalDateTime createdAt;
    private LocalDateTime updatedAt;
    private Double balance=0.0;
    @ManyToMany(fetch = FetchType.EAGER)
    @JoinTable(
            name = "user_roles",
            joinColumns = @JoinColumn(name = "user_id"),
            inverseJoinColumns = @JoinColumn(name = "role_id")
    )
    private Set<Role> roles;

    @Enumerated(EnumType.STRING)
    private Status status=Status.PENDING;

    @OneToMany(mappedBy = "seller",cascade = CascadeType.ALL)
    private List<Project>uploadedProjects=new ArrayList<>();

    @OneToMany(mappedBy = "buyer",cascade = CascadeType.ALL)
    private List<Purchase>purchases=new ArrayList<>();

    @OneToMany(mappedBy = "user",cascade = CascadeType.ALL)
    private List<Review>reviews=new ArrayList<>();

    @PrePersist
    public void onCreate() {
        this.createdAt = LocalDateTime.now();
        this.updatedAt = LocalDateTime.now();
    }

    @PreUpdate
    public void onUpdate() {
        this.updatedAt = LocalDateTime.now();
    }


    public boolean hasPurchased(Project project) {
        return purchases.stream()
                .anyMatch(p->p.getProject().getId().equals(project.getId())
                && p.canDownload());
    }

    /**
     * Add balance to user account
     * @param amount amount to add (must be positive)
     * @throws IllegalArgumentException if amount is negative or zero
     */
    public void addBalance(double amount) {
        if (amount <= 0) {
            throw new IllegalArgumentException("Balance addition amount must be positive, got: " + amount);
        }
        this.balance += amount;
    }

    /**
     * Deduct balance from user account
     * @param amount amount to deduct (must be positive)
     * @throws IllegalArgumentException if amount is negative, zero, or exceeds current balance
     */
    public void deductBalance(double amount) {
        if (amount <= 0) {
            throw new IllegalArgumentException("Balance deduction amount must be positive, got: " + amount);
        }
        if (this.balance < amount) {
            throw new IllegalArgumentException("Insufficient balance. Current: " + this.balance + ", Required: " + amount);
        }
        this.balance -= amount;
    }

}

package com.example.projecthub.service.admin;

import com.example.projecthub.dto.category.CategoryDTO;
import com.example.projecthub.dto.user.UserDetailsResponse;
import com.example.projecthub.model.Category;
import com.example.projecthub.model.Status;
import com.example.projecthub.model.User;
import com.example.projecthub.model.UserStatusHistory;
import com.example.projecthub.repository.CategoryRepository;
import com.example.projecthub.repository.UserRepository;
import com.example.projecthub.repository.UserStatusHistoryRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
public class AdminServiceImpl implements AdminService {

    private final UserRepository userRepository;
    private final UserStatusHistoryRepository userStatusHistoryRepository;
    private final CategoryRepository categoryRepository;

    @Override
    public void updateUserStatus(
            Long userId,
            Status newStatus,
            String reason,
            String changedBy
    ) {

        User user = userRepository.findById(userId)
                .orElseThrow(() -> new RuntimeException("User not found"));

        Status currentStatus = user.getStatus();

        //  VALIDATE TRANSITION (clean & professional)
        if (!currentStatus.canTransitionTo(newStatus)) {
            throw new IllegalStateException(
                    "Invalid status transition: " + currentStatus + " → " + newStatus
            );
        }

        //  SAVE HISTORY
        UserStatusHistory history = new UserStatusHistory();
        history.setUser(user);
        history.setOldStatus(currentStatus);
        history.setNewStatus(newStatus);
        history.setReason(reason);
        history.setChangedBy(changedBy);
        history.setChangedAt(LocalDateTime.now());

        userStatusHistoryRepository.save(history);

        // ✅ UPDATE USER STATUS (YOU MISSED THIS EARLIER)
        user.setStatus(newStatus);
        userRepository.save(user);
    }

    public Map<String, Object> getRecentlyJoinedUsersPaginated(int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by("createdAt").descending());
        Page<User> userPage = userRepository.findAllByOrderByCreatedAtDesc(pageable);

        // FIX: Changed from Positive.List to List and fixed toDto() call
        List<UserDetailsResponse> users = userPage.getContent().stream()
                .map(UserDetailsResponse::toDto)  // Changed from toDto() to ::toDto
                .collect(Collectors.toList());

        Map<String, Object> response = new HashMap<>();
        response.put("users", users);
        response.put("currentPage", userPage.getNumber());
        response.put("totalPages", userPage.getTotalPages());
        response.put("totalItems", userPage.getTotalElements());
        response.put("hasNext", userPage.hasNext());
        response.put("hasPrevious", userPage.hasPrevious());
        return response;
    }


    public Map<String, Object> getAllJoinedUsersPaginated(int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by("id").ascending());
        Page<User> userPage = userRepository.findAllByOrderByIdAsc(pageable);

        // FIX: Changed from Positive.List to List and fixed toDto() call
        List<UserDetailsResponse> users = userPage.getContent().stream()
                .map(UserDetailsResponse::toDto)  // Changed from toDto() to ::toDto
                .collect(Collectors.toList());

        Map<String, Object> response = new HashMap<>();
        response.put("users", users);
        response.put("currentPage", userPage.getNumber());
        response.put("totalPages", userPage.getTotalPages());
        response.put("totalItems", userPage.getTotalElements());
        response.put("hasNext", userPage.hasNext());
        response.put("hasPrevious", userPage.hasPrevious());
        return response;
    }



    //category
    public CategoryDTO createCategory(CategoryDTO dto) {
        Category category = new Category();
        category.setName(dto.getName());
        category.setDescription(dto.getDescription());
        Category savedCategory = categoryRepository.save(category);
        return CategoryDTO.toDto(savedCategory);
    }

    public Map<String, Object> getRecentAddedCategoriesPaginated(int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by("createdAt").descending());
        Page<Category> categoryPage = categoryRepository.findAllByOrderByCreatedAtDesc(pageable);
        List<CategoryDTO> categories = categoryPage.getContent().stream()
                .map(CategoryDTO::toDto).collect(Collectors.toList());
        Map<String, Object> response = new HashMap<>();
        response.put("categories", categories);
        response.put("currentPage", categoryPage.getNumber());
        response.put("totalPages", categoryPage.getTotalPages());
        response.put("totalItems", categoryPage.getTotalElements());
        response.put("hasNext", categoryPage.hasNext());
        response.put("hasPrevious", categoryPage.hasPrevious());
        return response;
    }

    @Override
    public List<CategoryDTO> getAllCategory() {
        return categoryRepository.findAll()
                .stream()
                .map(CategoryDTO::toDto)
                .collect(Collectors.toList());
    }

}

