        // ✅ UPDATE USER STATUS (YOU MISSED THIS EARLIER)
        user.setStatus(newStatus);
        userRepository.save(user);
    }

    /**
     * Helper method to paginate users and build response map
     */
    private Map<String, Object> buildUserPaginationResponse(Page<User> userPage) {
        List<UserDetailsResponse> users = userPage.getContent().stream()
                .map(UserDetailsResponse::toDto)
                .collect(Collectors.toList());

        Map<String, Object> response = new HashMap<>();
        response.put("users", users);
        response.put("currentPage", userPage.getNumber());
        response.put("totalPages", userPage.getTotalPages());
        response.put("totalItems", userPage.getTotalElements());
        response.put("hasNext", userPage.hasNext());
        response.put("hasPrevious", userPage.hasPrevious());
        return response;
    }

    public Map<String, Object> getRecentlyJoinedUsersPaginated(int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by("createdAt").descending());
        Page<User> userPage = userRepository.findAllByOrderByCreatedAtDesc(pageable);
        return buildUserPaginationResponse(userPage);
    }

    public Map<String, Object> getAllJoinedUsersPaginated(int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by("id").ascending());
        Page<User> userPage = userRepository.findAllByOrderByIdAsc(pageable);
        return buildUserPaginationResponse(userPage);
    }

    //category
    public CategoryDTO createCategory(CategoryDTO dto) {
        Category category = new Category();
        category.setName(dto.getName());
        category.setDescription(dto.getDescription());
        Category savedCategory = categoryRepository.save(category);
        return CategoryDTO.toDto(savedCategory);
    }

    public Map<String, Object> getRecentAddedCategoriesPaginated(int page, int size) {
        Pageable pageable = PageRequest.of(page, size, Sort.by("createdAt").descending());
        Page<Category> categoryPage = categoryRepository.findAllByOrderByCreatedAtDesc(pageable);
        List<CategoryDTO> categories = categoryPage.getContent().stream()
                .map(CategoryDTO::toDto).collect(Collectors.toList());
        Map<String, Object> response = new HashMap<>();
        response.put("categories", categories);
        response.put("currentPage", categoryPage.getNumber());
        response.put("totalPages", categoryPage.getTotalPages());
        response.put("totalItems", categoryPage.getTotalElements());
        response.put("hasNext", categoryPage.hasNext());
        response.put("hasPrevious", categoryPage.hasPrevious());
        return response;
    }

    @Override
    public List<CategoryDTO> getAllCategory() {
        return categoryRepository.findAll()
                .stream()
                .map(CategoryDTO::toDto)
                .collect(Collectors.toList());
    }

}

package com.example.projecthub.service.auth;

import com.example.projecthub.dto.user.AuthResponse;
import com.example.projecthub.dto.user.LoginRequest;
import com.example.projecthub.dto.user.RegisterRequest;
import com.example.projecthub.jwt.JwtUtils;
import com.example.projecthub.model.Role;
import com.example.projecthub.model.User;
import com.example.projecthub.repository.RoleRepository;
import com.example.projecthub.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.HashSet;
import java.util.Set;
import java.util.stream.Collectors;

/**
 * Authentication Service Implementation
 * Handles user registration, login, and token refresh operations
 */
@Service
@RequiredArgsConstructor
@Slf4j
public class AuthServiceImpl implements AuthService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final RoleRepository roleRepository;
    private final JwtUtils jwtUtils;
    private final UserDetailsService userDetailsService;
    private final AuthenticationManager authenticationManager;

    /**
     * Register a new user with BUYER role by default
     * 
     * @param registerRequest contains username, email, password
     * @return AuthResponse with access token, refresh token, and user info
     * @throws RuntimeException if username or email already exists
     */
    @Override
    public AuthResponse registerUser(RegisterRequest registerRequest) {
        if (userRepository.existsByUsername(registerRequest.getUsername())) {
            log.warn("Registration failed: Username already taken - {}", registerRequest.getUsername());
            throw new RuntimeException("Username is already taken");
        }

        if (userRepository.existsByEmail(registerRequest.getEmail())) {
            log.warn("Registration failed: Email already taken - {}", registerRequest.getEmail());
            throw new RuntimeException("Email is already taken");
        }

        User user = new User();
        user.setUsername(registerRequest.getUsername());
        user.setEmail(registerRequest.getEmail());
        user.setPassword(passwordEncoder.encode(registerRequest.getPassword()));

        Role buyerRole = roleRepository.findByName("ROLE_BUYER");
        Set<Role> roles = new HashSet<>();
        roles.add(buyerRole);
        user.setRoles(roles);

        User savedUser = userRepository.save(user);
        log.info("User registered successfully: {}", savedUser.getUsername());

        UserDetails userDetails = userDetailsService.loadUserByUsername(savedUser.getUsername());
        String accessToken = jwtUtils.generateAccessToken(userDetails);
        String refreshToken = jwtUtils.generateRefreshToken(userDetails);

        return new AuthResponse(
            accessToken, 
            refreshToken, 
            savedUser.getUsername(), 
            savedUser.getId(), 
            user.getEmail(),
            savedUser.getRoles().stream()
                .map(Role::getName)
                .collect(Collectors.toSet())
        );
    }

    /**
     * Authenticate user with username and password
     * 
     * @param loginRequest contains username and password
     * @return AuthResponse with access token, refresh token, and user info
     * @throws UsernameNotFoundException if user is not found
     */
    @Override
    public AuthResponse loginUser(LoginRequest loginRequest) {
        try {
            Authentication authenticate = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(
                    loginRequest.getUsername(), 
                    loginRequest.getPassword()
                )
            );

            UserDetails userDetails = (UserDetails) authenticate.getPrincipal();
            String accessToken = jwtUtils.generateAccessToken(userDetails);
            String refreshToken = jwtUtils.generateRefreshToken(userDetails);

            User user = userRepository.findByUsername(userDetails.getUsername())
                .orElseThrow(() -> new UsernameNotFoundException("Username not found"));

            log.info("User logged in successfully: {}", user.getUsername());

            return new AuthResponse(
                accessToken,
                refreshToken,
                user.getUsername(),
                user.getId(), 
                user.getEmail(),
                user.getRoles().stream()
                    .map(Role::getName)
                    .collect(Collectors.toSet())
            );
        } catch (Exception e) {
            log.error("Login failed for user: {}", loginRequest.getUsername(), e);
            throw new RuntimeException("Invalid credentials");
        }
    }

    /**
     * Refresh access token using a valid refresh token
     * 
     * @param refreshToken the refresh token from the request
     * @return AuthResponse with new access token and same refresh token
     * @throws RuntimeException if refresh token is invalid or expired
     */
    @Override
    public AuthResponse refreshToken(String refreshToken) {
        try {
            String username = jwtUtils.extractUsername(refreshToken);
            UserDetails userDetails = userDetailsService.loadUserByUsername(username);

            if (!jwtUtils.isTokenValid(refreshToken, userDetails)) {
                log.warn("Invalid refresh token for user: {}", username);
                throw new RuntimeException("Invalid or expired refresh token");
            }

            String newAccessToken = jwtUtils.generateAccessToken(userDetails);

            User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User not found"));

            log.info("Token refreshed successfully for user: {}", username);

            return new AuthResponse(
                newAccessToken,
                refreshToken,
                user.getUsername(),
                user.getId(),
                user.getEmail(),
                user.getRoles().stream()
                    .map(Role::getName)
                    .collect(Collectors.toSet())
            );
        } catch (Exception e) {
            log.error("Error refreshing token: {}", e.getMessage(), e);
            throw new RuntimeException("Error refreshing token: " + e.getMessage());
        }
    }

}

package com.example.projecthub.service.auth;

import com.example.projecthub.dto.user.AuthResponse;
import com.example.projecthub.dto.user.LoginRequest;
import com.example.projecthub.dto.user.RegisterRequest;
import com.example.projecthub.jwt.JwtUtils;
import com.example.projecthub.model.Role;
import com.example.projecthub.model.User;
import com.example.projecthub.repository.RoleRepository;
import com.example.projecthub.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.security.core.userdetails.UserDetailsService;
import org.springframework.security.core.userdetails.UsernameNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.util.HashSet;
import java.util.Set;
import java.util.stream.Collectors;

/**
 * Authentication Service Implementation
 * Handles user registration, login, and token refresh operations
 */
@Service
@RequiredArgsConstructor
@Slf4j
public class AuthServiceImpl implements AuthService {
    
    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final RoleRepository roleRepository;
    private final JwtUtils jwtUtils;
    private final UserDetailsService userDetailsService;
    private final AuthenticationManager authenticationManager;

    /**
     * Register a new user with BUYER role by default
     * 
     * @param registerRequest contains username, email, password
     * @return AuthResponse with access token, refresh token, and user info
     * @throws RuntimeException if username or email already exists
     */
    @Override
    public AuthResponse registerUser(RegisterRequest registerRequest) {
        if (userRepository.existsByUsername(registerRequest.getUsername())) {
            log.warn("Registration failed: Username already taken - {}", registerRequest.getUsername());
            throw new RuntimeException("Username is already taken");
        }
        
        if (userRepository.existsByEmail(registerRequest.getEmail())) {
            log.warn("Registration failed: Email already taken - {}", registerRequest.getEmail());
            throw new RuntimeException("Email is already taken");
        }

        User user = new User();
        user.setUsername(registerRequest.getUsername());
        user.setEmail(registerRequest.getEmail());
        user.setPassword(passwordEncoder.encode(registerRequest.getPassword()));

        Role buyerRole = roleRepository.findByName("ROLE_BUYER");
        Set<Role> roles = new HashSet<>();
        roles.add(buyerRole);
        user.setRoles(roles);
        
        User savedUser = userRepository.save(user);
        log.info("User registered successfully: {}", savedUser.getUsername());

        UserDetails userDetails = userDetailsService.loadUserByUsername(savedUser.getUsername());
        String accessToken = jwtUtils.generateAccessToken(userDetails);
        String refreshToken = jwtUtils.generateRefreshToken(userDetails);
        
        return new AuthResponse(
            accessToken, 
            refreshToken, 
            savedUser.getUsername(), 
            savedUser.getId(), 
            user.getEmail(),
            savedUser.getRoles().stream()
                .map(Role::getName)
                .collect(Collectors.toSet())
        );
    }

    /**
     * Authenticate user with username and password
     * 
     * @param loginRequest contains username and password
     * @return AuthResponse with access token, refresh token, and user info
     * @throws UsernameNotFoundException if user is not found
     */
    @Override
    public AuthResponse loginUser(LoginRequest loginRequest) {
        try {
            Authentication authenticate = authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(
                    loginRequest.getUsername(), 
                    loginRequest.getPassword()
                )
            );
            
            UserDetails userDetails = (UserDetails) authenticate.getPrincipal();
            String accessToken = jwtUtils.generateAccessToken(userDetails);
            String refreshToken = jwtUtils.generateRefreshToken(userDetails);

            User user = userRepository.findByUsername(userDetails.getUsername())
                .orElseThrow(() -> new UsernameNotFoundException("Username not found"));

            log.info("User logged in successfully: {}", user.getUsername());
            
            return new AuthResponse(
                accessToken,
                refreshToken,
                user.getUsername(),
                user.getId(), 
                user.getEmail(),
                user.getRoles().stream()
                    .map(Role::getName)
                    .collect(Collectors.toSet())
            );
        } catch (Exception e) {
            log.error("Login failed for user: {}", loginRequest.getUsername(), e);
            throw new RuntimeException("Invalid credentials");
        }
    }

    /**
     * Refresh access token using a valid refresh token
     * 
     * @param refreshToken the refresh token from the request
     * @return AuthResponse with new access token and same refresh token
     * @throws RuntimeException if refresh token is invalid or expired
     */
    @Override
    public AuthResponse refreshToken(String refreshToken) {
        try {
            if (refreshToken == null || refreshToken.isEmpty()) {
                log.warn("Refresh token is null or empty");
                throw new RuntimeException("Refresh token cannot be null or empty");
            }

            String username = jwtUtils.extractUsername(refreshToken);

            if (username == null || username.isEmpty()) {
                log.warn("Failed to extract username from refresh token");
                throw new RuntimeException("Invalid refresh token: cannot extract username");
            }

            UserDetails userDetails = userDetailsService.loadUserByUsername(username);

            if (!jwtUtils.isRefreshTokenValid(refreshToken, userDetails)) {
                log.warn("Invalid refresh token for user: {}", username);
                throw new RuntimeException("Invalid or expired refresh token");
            }

            String newAccessToken = jwtUtils.generateAccessToken(userDetails);

            User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User not found"));

            log.info("Token refreshed successfully for user: {}", username);

            return new AuthResponse(
                newAccessToken,
                refreshToken,
                user.getUsername(),
                user.getId(),
                user.getEmail(),
                user.getRoles().stream()
                    .map(Role::getName)
                    .collect(Collectors.toSet())
            );
        } catch (Exception e) {
            log.error("Error refreshing token: {}", e.getMessage(), e);
            throw new RuntimeException("Error refreshing token: " + e.getMessage());
        }
    }

}

package com.example.projecthub.service.download;

import com.example.projecthub.model.ProjectFile;
import com.example.projecthub.repository.ProjectFileRepository;
import com.example.projecthub.repository.PurchaseRepository;
import jakarta.servlet.http.HttpServletResponse;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.core.io.Resource;
import org.springframework.core.io.UrlResource;
import org.springframework.http.HttpHeaders;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.util.StreamUtils;
import org.springframework.web.servlet.mvc.method.annotation.StreamingResponseBody;

import java.io.BufferedOutputStream;
import java.io.IOException;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.zip.ZipEntry;
import java.util.zip.ZipOutputStream;

@Service
@RequiredArgsConstructor
@Slf4j
public class DownloadServiceImpl implements DownloadService {

    private final ProjectFileRepository projectFileRepository;
    private final PurchaseRepository purchaseRepository;


    @Value("${filePath}")          // ✅ declared here — used in both methods
    private String filePath;

    // --- single file download ---
    @Transactional
    public Resource downloadProjectFile(Long fileId, Long userId) throws IOException {
        ProjectFile projectFile = projectFileRepository.findById(fileId)
                .orElseThrow(() -> new RuntimeException("File not found with ID: " + fileId));

        boolean hasPurchased = purchaseRepository.existsByBuyerIdAndProjectId(userId, projectFile.getProject().getId());
        if (!hasPurchased) throw new RuntimeException("Access denied.");

        String filename = projectFile.getFileUrl().replace("/files/", "");
        Path resolvedPath = Paths.get(filePath).resolve(filename).normalize();  // ✅ filePath used here

        if (!resolvedPath.startsWith(Paths.get(filePath).normalize()))
            throw new RuntimeException("Invalid file path.");

        Resource resource = new UrlResource(resolvedPath.toUri());
        if (!resource.exists() || !resource.isReadable())
            throw new RuntimeException("File not found on server.");

        projectFile.setDownloadCount(
                projectFile.getDownloadCount() == null ? 1 : projectFile.getDownloadCount() + 1
        );
        projectFileRepository.save(projectFile);
        return resource;
    }

    // --- download all as ZIP ---
    @Transactional
    public StreamingResponseBody downloadAllProjectFiles(Long projectId, Long userId, HttpServletResponse response) throws IOException {

        boolean hasPurchased = purchaseRepository.existsByBuyerIdAndProjectId(userId, projectId);
        if (!hasPurchased) throw new RuntimeException("Access denied. You have not purchased this project.");

        List<ProjectFile> projectFiles = projectFileRepository.findAllByProjectId(projectId);
        if (projectFiles.isEmpty()) throw new RuntimeException("No files found for project ID: " + projectId);

        response.setContentType("application/zip");
        response.setHeader(HttpHeaders.CONTENT_DISPOSITION,
                "attachment; filename=\"project-" + projectId + ".zip\"");

        return outputStream -> {
            try (ZipOutputStream zipOut = new ZipOutputStream(new BufferedOutputStream(outputStream))) {
                for (ProjectFile projectFile : projectFiles) {
                    String filename = projectFile.getFileUrl().replace("/files/", "");
                    Path resolvedPath = Paths.get(filePath).resolve(filename).normalize();  // ✅ filePath used here

                    if (!resolvedPath.startsWith(Paths.get(filePath).normalize())) {
                        log.warn("Skipping suspicious path: {}", filename);
                        continue;
                    }

                    Resource resource = new UrlResource(resolvedPath.toUri());
                    if (!resource.exists() || !resource.isReadable()) {
                        log.warn("Skipping missing file: {}", filename);
                        continue;
                    }

                    String entryName = projectFile.getFileName() != null ? projectFile.getFileName() : filename;
                    zipOut.putNextEntry(new ZipEntry(entryName));
                    StreamUtils.copy(resource.getInputStream(), zipOut);
                    zipOut.closeEntry();

                    projectFile.setDownloadCount(
                            projectFile.getDownloadCount() == null ? 1 : projectFile.getDownloadCount() + 1
                    );
                    projectFileRepository.save(projectFile);
                    log.info("Added to ZIP: {} for project {}", entryName, projectId);
                }
            }
        };
    }
}

